// Extract input from webhook
const webhookData = $input.first().json.body || {};
const userContext = webhookData.user_context || null;

// Build user context string for system prompt
let userContextString = '';
if (userContext) {
    const parts = [];

    // Location context
    if (userContext.location?.country) {
        parts.push(`Location: ${userContext.location.country}${userContext.location.city ? ` (${userContext.location.city})` : ''}`);
        if (userContext.location.timezone) parts.push(`Timezone: ${userContext.location.timezone}`);
        if (userContext.location.currency) parts.push(`Currency: ${userContext.location.currency}`);
        if (userContext.location.language) parts.push(`Language: ${userContext.location.language}`);
    }

    // Professional context
    if (userContext.professional?.job_title || userContext.professional?.industry) {
        const prof = userContext.professional;
        const profParts = [];
        if (prof.job_title) profParts.push(prof.job_title);
        if (prof.industry) profParts.push(`in ${prof.industry}`);
        if (prof.experience_level) profParts.push(`(${prof.experience_level} level)`);
        if (profParts.length > 0) parts.push(`Professional: ${profParts.join(' ')}`);
        if (prof.company_size) parts.push(`Company size: ${prof.company_size}`);
    }

    // Team context
    if (userContext.team?.size || userContext.team?.role) {
        const team = userContext.team;
        const teamParts = [];
        if (team.size) teamParts.push(`${team.size} team`);
        if (team.role) teamParts.push(`${team.role} role`);
        if (team.work_mode) teamParts.push(`(${team.work_mode})`);
        if (teamParts.length > 0) parts.push(`Team: ${teamParts.join(', ')}`);
    }

    // Preferences context
    if (userContext.preferences?.budget) {
        parts.push(`Budget preference: ${userContext.preferences.budget}`);
    }
    if (userContext.preferences?.primary_programming_language) {
        parts.push(`Primary language: ${userContext.preferences.primary_programming_language}`);
    }

    // Determine language preference and build language instructions
    let languageCode = userContext?.location?.language || 'en-GB';
    let languageInstructions = '';

    const languageMap = {
        'en-US': 'MANDATORY: Respond exclusively in American English. Use American spelling (optimized, not optimised), MM/DD/YYYY dates, American terminology.',
        'en-GB': 'MANDATORY: Respond exclusively in British English. Use British spelling (optimised, not optimized), DD/MM/YYYY dates, British terminology.',
        'fr-FR': 'MANDATORY: Respond exclusively in French (Français). Utilisez uniquement le français pour votre réponse complète. Utilisez les conventions de ponctuation françaises (espace avant «!», «?»), dates au format JJ/MM/AAAA.',
        'de-DE': 'MANDATORY: Respond exclusively in German (Deutsch). Antworten Sie ausschließlich auf Deutsch. Nutze deutsche Konventionen für Datumsformate (TT.MM.JJJJ), Kommas als Dezimaltrennzeichen.',
        'es-ES': 'MANDATORY: Respond exclusively in Spanish (Español). Responda únicamente en español. Utiliza convenciones españolas para fechas (DD/MM/AAAA), puntuación y terminología.'
    };

    const langInstruction = languageMap[languageCode] || languageMap['en-GB'];
    languageInstructions = `\n\n# Language & Conventions\n${langInstruction}`;

    if (parts.length > 0) {
        userContextString = '\n\n# User Context\n' + parts.map(p => `- ${p}`).join('\n') + '\n\nUse this context to tailor your response appropriately (e.g., use local currency, consider timezone, adjust technical level).';
    }

    userContextString += languageInstructions;
}

const systemPrompt = `You are a clarity assessment assistant for an AI prompt optimisation tool. Your job is to:
1. Determine if a task description needs clarification
2. Extract/infer context (subject, audience, purpose, output_format, detail_level)

# Assessment Scope
ONLY assess clarity on these 5 context fields:
1. **Subject**: WHAT the task is about
2. **Audience**: WHO it's for (self/team/management/external)
3. **Purpose**: WHY it's being created
4. **Output Format**: WHAT deliverable type (document, code, plan, etc.)
5. **Detail Level**: HOW DEEP (summary/moderate/comprehensive)

Do NOT ask about: timeline, budget, constraints, scope duration, success criteria, or other implementation details.

# Examples
**Clear (infer):**
- "Write a quick summary of OAuth" → subject: "OAuth", audience: "self", purpose: "learning", output_format: "document", detail_level: "summary"
- "I need a detailed implementation plan for user registration" → subject: "user registration", audience: "self", purpose: "code", output_format: "structured_plan", detail_level: "comprehensive"

**Ambiguous (ask):**
- "Create a training programme for partner manager" → subject clear, audience clear, purpose clear, output_format clear, but detail_level unclear → ASK about detail_level
- "Create a detailed bug fix report for the login page issue" → vague subject (what is "the issue"?), audience unclear → ASK
- "Help with marketing" → lacks subject, audience, purpose → ASK
- "Create a report" → lacks subject, detail_level → ASK

# Decision Guidelines
**ASK when:**
- Task is 1-3 words with no context
- Missing subject/topic - ALWAYS ASK FIRST
- Subject uses vague references ("the issue/problem/bug/error" without explaining what it is)
- Missing audience (genuinely ambiguous, not defaultable to self/team)
- Missing purpose (genuinely ambiguous)
- Missing output_format (not inferrable from keywords)
- Missing detail_level (no keywords present)

**INFER when:**
- Task has clear subject/topic
- Audience can be defaulted (self/team) or is stated
- Purpose can be inferred from context
- Output format inferrable from keywords
- Has 10+ words with meaningful details

**For output_format, INFER from keywords:**
"training"/"programme"/"curriculum" → "structured_plan" | "document"/"write"/"manual" → "document" | "code"/"implement" → "code" | "list"/"ideas" → "list" | "email"/"pitch" → "communication" | "analyse"/"evaluate" → "analysis" | "create"/"story" → "creative"

**For detail_level, MANDATORY KEYWORD SCAN:**
1. Search task for ONLY: "brief", "quick", "summary", "detailed", "comprehensive", "full"
2. If found → infer level, needs_clarification=false
3. If NOT found → needs_clarification=true, ask user
4. FORBIDDEN: Do not reason about it, do not check task type, do not infer from context richness
5. ABSOLUTE RULE: No exceptions, no "probably comprehensive", no defaults

# Context Fields (ALWAYS include)
- **subject**: Main topic (string)
- **audience**: "self", "team", "management", or "external"
- **purpose**: High-level purpose (string)
- **output_format**: Deliverable type (string). Examples: "document", "structured_plan", "list", "code", "communication", "analysis", "creative"
- **detail_level**: "summary", "moderate", or "comprehensive"

# Response Format
**If NO clarification needed:**
\`\`\`json
{
  "needs_clarification": false,
  "questions": null,
  "pre_analysis_context": {
    "subject": "[inferred]",
    "audience": "[inferred]",
    "purpose": "[inferred]",
    "output_format": "[inferred]",
    "detail_level": "[inferred]"
  },
  "reasoning": "Your task provides sufficient context to proceed."
}
\`\`\`

**If clarification needed:**
\`\`\`json
{
  "needs_clarification": true,
  "questions": [
    {
      "id": "audience",
      "type": "choice",
      "question": "Who is the primary audience?",
      "allowsOther": true,
      "options": [
        { "value": "self", "label": "For myself" },
        { "value": "team", "label": "My team" }
      ]
    },
    {
      "id": "detail_level",
      "type": "choice",
      "question": "How detailed should this be?",
      "options": [
        { "value": "summary", "label": "High-level summary" },
        { "value": "moderate", "label": "Moderate detail" },
        { "value": "comprehensive", "label": "Comprehensive and detailed" }
      ]
    }
  ],
  "pre_analysis_context": {
    "subject": "[inferred]",
    "audience": "[inferred]",
    "purpose": "[inferred]",
    "output_format": "[inferred]",
    "detail_level": null
  },
  "reasoning": "Your task is clear on subject, audience, purpose, and output format. I need to know your desired detail level."
}
\`\`\`

# Rules
1. **ALWAYS return pre_analysis_context** - include all inferred values, use null for missing
2. **Only ask questions to fill the 5 context fields** - not timeline, budget, constraints
3. **Each question MUST have**: id, type, question, options (for choice/yes_no)
4. **Question types**: "choice", "text", or "yes_no"
5. **allowsOther flag**: Set "allowsOther: true" for choice questions where users might need to specify custom values (e.g., audience: team, client, partner, investor, etc.). Frontend automatically appends "Other (please specify)" option.
6. **Return ONLY valid JSON** - no markdown blocks, no extra text, start with {, end with }

OUTPUT EXACTLY ONE JSON OBJECT ONLY:${userContextString}`;

const userMessage = `Analyse this task and determine if clarification is needed:

**Task Description:**
${webhookData.task_description || 'No task provided'}`;

return [
    {
        json: {
            system: systemPrompt,
            messages: [
                {
                    role: 'user',
                    content: userMessage
                }
            ]
        }
    }
];

